import path from 'path';

/**
 * Parse the URL string
 */
function parseURL(s: string): URL | undefined {
    let url;
    try {
        url = new URL(s);
    } catch (error) {
        console.error(error);
    }
    return url;
}

function isSameOrigin(a: string, b: string) {
    const urlA = parseURL(a);
    const urlB = parseURL(b);
    if (!urlA || !urlB) {
        return false;
    }
    if (urlA.origin === urlB.origin) {
        return true;
    }
    if (
        urlA.protocol === urlB.protocol &&
        urlA.hostname === urlB.hostname &&
        urlA.port === urlB.port
    ) {
        return true;
    }
    return false;
}

export default function getPublicPath() {

    const currentScript = document.currentScript as HTMLScriptElement;

    if (currentScript) {
        const baseURI = currentScript.baseURI;
        let scriptUrl = currentScript.src;

        if (isSameOrigin(scriptUrl, baseURI)) {
            scriptUrl = path.relative(path.dirname(baseURI), scriptUrl);
        }

        return scriptUrl.replace(/#.*$/, '').replace(/\?.*$/, '').replace(/\/[^\/]+$/, '/');
    }
    throw new Error('Automatic publicPath is not supported in this browser');
}
